import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly handling user input by escaping special characters
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        // Outputting the sanitized input to a web page
        PrintWriter out = new PrintWriter(System.out);
        out.println("<html>");
        out.println("<head><title>XSS Fixed Example</title></head>");
        out.println("<body>");
        out.println("Sanitized User Input: " + sanitizedInput);
        out.println("</body>");
        out.println("</html>");
    }
}

